@startuml
title Subscribe & Save Debugging Classroom Activity

class App {
    title "App"
    getAmazonProductService() : AmazonProductService
    getAmazonIdentityService() : AmazonIdentityService
    getSubscriptionDAO() : SubscriptionDAO
    getSubscriptionFileStorage() : SubscriptionFileStorage
    getSubscriptionService() : SubscriptionService
}

class Subscription {
    title "Subscription"
    String id
    String customerId
    String asin
    int frequency
    getID() : String
    setId(id : String) : void
    getCustomerId() : String
    getAsin() : String
    getFrequency() : int
    toString() : String
}

class SubscriptionDebugUtil {
    title "SubscriptionDebugUtil"
    main(String[] args) : void
}

class SubscriptionService {
    title "SubscriptionService"
    subscribe(customerId : String, asin : String, frequency : int) : Subscription
    getSubscription(subscriptionId : String) : Subscription
}

class AmazonProductService {
    title "AmazonProductService"
    getProductByAsin(asin : String) : Product
}

class AmazonIdentityService {
    title "AmazonIdentityService"
    validateCustomer(customerId : String) : boolean
}

class SubscriptionDAO {
    title "SubscriptionDAO"
    createSubscription(customerId : String, asin : String, frequency : int) : Subscription
    getSubscription(subscriptionId : String) : Subscription
}

class SubscriptionFileStorage {
    title "SubscriptionFileStorage"
    getSubscriptionById(subscriptionId : String) : Subscription
    writeSubscription(subscription : Subscription) : Subscription
}

class SubscriptionDebugUtil {
    title "SubscriptionDebugUtil"
    main(String[] args) : void
}

SubscriptionService --* SubscriptionDAO : "1" *--
SubscriptionService -- AmazonProductService : "1" *--
SubscriptionService -- AmazonIdentityService : "1" *--
SubscriptionDAO --* SubscriptionFileStorage : "1" *--

@enduml
